    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder
        //     {
        //         "orderId": 60667653330,
        //         "clientOrderId": 0,
        //         "type": "LIMIT",
        //         "price": 60,
        //         "quantity": 0.1,
        //         "amount": null,
        //         "bidAskLevel": null,
        //         "timestamp": 1751871779855
        //     }
        //
        // createOrder - algo
        //     {
        //         "orderId": "1578938",
        //         "clientOrderId": "0",
        //         "algoType": "STOP_LOSS",
        //         "quantity": "0.1",
        //         "timestamp": "1686149372216"
        //     }
        //
        // fetchOrder
        //     {
        //         "orderId": 60780315704,
        //         "clientOrderId": 0,
        //         "symbol": "SPOT_LTC_USDT",
        //         "orderTag": "default",
        //         "side": "BUY",
        //         "quantity": 0.1,
        //         "amount": null,
        //         "type": "LIMIT",
        //         "status": "NEW",
        //         "price": 60,
        //         "executed": 0,
        //         "visible": 0.1,
        //         "averageExecutedPrice": 0,
        //         "totalFee": 0,
        //         "feeAsset": "LTC",
        //         "totalRebate": 0,
        //         "rebateAsset": "USDT",
        //         "reduceOnly": false,
        //         "createdTime": "1752049062.496",
        //         "realizedPnl": null,
        //         "positionSide": "BOTH",
        //         "bidAskLevel": null
        //     }
        //
        // fetchOrder - algo
        //     {
        //         "algoOrderId": 10399260,
        //         "clientAlgoOrderId": 0,
        //         "rootAlgoOrderId": 10399260,
        //         "parentAlgoOrderId": 0,
        //         "symbol": "SPOT_LTC_USDT",
        //         "algoOrderTag": "default",
        //         "algoType": "TAKE_PROFIT",
        //         "side": "BUY",
        //         "quantity": 0.1,
        //         "isTriggered": false,
        //         "triggerPrice": 65,
        //         "triggerStatus": "USELESS",
        //         "type": "LIMIT",
        //         "rootAlgoStatus": "NEW",
        //         "algoStatus": "NEW",
        //         "triggerPriceType": "MARKET_PRICE",
        //         "price": 60,
        //         "triggerTime": "0",
        //         "totalExecutedQuantity": 0,
        //         "visibleQuantity": 0.1,
        //         "averageExecutedPrice": 0,
        //         "totalFee": 0,
        //         "feeAsset": "",
        //         "totalRebate": 0,
        //         "rebateAsset": "",
        //         "reduceOnly": false,
        //         "createdTime": "1752049747.732",
        //         "updatedTime": "1752049747.732",
        //         "positionSide": "BOTH"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = null;
        Object timestrampString = this.safeString(order, "createdTime");
        if (Helpers.isTrue(!Helpers.isEqual(timestrampString, null)))
        {
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(timestrampString, "."), 0)))
            {
                timestamp = this.safeTimestamp(order, "createdTime"); // algo orders
            } else
            {
                timestamp = this.safeInteger(order, "createdTime"); // regular orders
            }
        }
        if (Helpers.isTrue(Helpers.isEqual(timestamp, null)))
        {
            timestamp = this.safeInteger(order, "timestamp");
        }
        Object orderId = this.safeString2(order, "orderId", "algoOrderId");
        Object clientOrderId = this.omitZero(((String)this.safeString2(order, "clientOrderId", "clientAlgoOrderId"))); // Somehow, this always returns 0 for limit order
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object price = this.safeString(order, "price");
        Object amount = this.safeString(order, "quantity"); // This is base amount
        Object cost = this.safeString(order, "amount"); // This is quote amount
        Object orderType = this.safeStringLower(order, "type");
        Object status = this.safeValue2(order, "status", "algoStatus");
        Object side = this.safeStringLower(order, "side");
        Object filled = this.omitZero(this.safeValue2(order, "executed", "totalExecutedQuantity"));
        Object average = this.omitZero(((String)this.safeString(order, "averageExecutedPrice")));
        // const remaining = Precise.stringSub (cost, filled);
        Object fee = this.safeNumber(order, "totalFee");
        Object feeCurrency = this.safeString(order, "feeAsset");
        Object triggerPrice = this.safeNumber(order, "triggerPrice");
        Object lastUpdateTimestampString = this.safeString(order, "updatedTime");
        Object lastUpdateTimestamp = null;
        if (Helpers.isTrue(!Helpers.isEqual(lastUpdateTimestampString, null)))
        {
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(lastUpdateTimestampString, "."), 0)))
            {
                lastUpdateTimestamp = this.safeTimestamp(order, "updatedTime"); // algo orders
            } else
            {
                lastUpdateTimestamp = this.safeInteger(order, "updatedTime"); // regular orders
            }
        }
        final Object finalTimestamp = timestamp;
        final Object finalLastUpdateTimestamp = lastUpdateTimestamp;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", orderId );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", finalTimestamp );
            put( "datetime", WooCore.this.iso8601(finalTimestamp) );
            put( "lastTradeTimestamp", null );
            put( "lastUpdateTimestamp", finalLastUpdateTimestamp );
            put( "status", WooCore.this.parseOrderStatus(status) );
            put( "symbol", symbol );
            put( "type", orderType );
            put( "timeInForce", WooCore.this.parseTimeInForce(orderType) );
            put( "postOnly", null );
            put( "reduceOnly", WooCore.this.safeBool(order, "reduceOnly") );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", triggerPrice );
            put( "takeProfitPrice", null );
            put( "stopLossPrice", null );
            put( "average", average );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", null );
            put( "cost", cost );
            put( "trades", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", fee );
                put( "currency", feeCurrency );
            }} );
            put( "info", order );
        }}, market);
    }

    public Object parseOrderStatus(Object status)
    {
        if (Helpers.isTrue(!Helpers.isEqual(status, null)))
        {
            Object statuses = new java.util.HashMap<String, Object>() {{
                put( "NEW", "open" );
                put( "FILLED", "closed" );
                put( "CANCEL_SENT", "canceled" );
                put( "CANCEL_ALL_SENT", "canceled" );
                put( "CANCELLED", "canceled" );
                put( "PARTIAL_FILLED", "open" );
                put( "REJECTED", "rejected" );
                put( "INCOMPLETE", "open" );
                put( "COMPLETED", "closed" );
            }};
            return this.safeString(statuses, status, status);
        }
        return status;
    }

