    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        // v1PrivateGetPositionSymbol
        //     {
        //         "symbol": "PERP_ETH_USDT",
        //         "position_side": "BOTH",
        //         "leverage": 10,
        //         "margin_mode": "CROSS",
        //         "average_open_price": 3139.9,
        //         "isolated_margin_amount": 0.0,
        //         "isolated_margin_token": "",
        //         "opening_time": "1720627963.094",
        //         "mark_price": 3155.19169891,
        //         "pending_short_qty": 0.0,
        //         "pending_long_qty": 0.0,
        //         "holding": -0.7,
        //         "pnl_24_h": 0.0,
        //         "est_liq_price": 9107.40055552,
        //         "settle_price": 3151.0319904,
        //         "success": true,
        //         "fee_24_h": 0.0,
        //         "isolated_frozen_long": 0.0,
        //         "isolated_frozen_short": 0.0,
        //         "timestamp": "1720867502.544"
        //     }
        //
        // v3PrivateGetPositions
        //     {
        //         "symbol": "PERP_LTC_USDT",
        //         "holding": "0.1",
        //         "pendingLongQty": "0",
        //         "pendingShortQty": "0",
        //         "settlePrice": "96.87",
        //         "averageOpenPrice": "96.87",
        //         "pnl24H": "0",
        //         "fee24H": "0.0048435",
        //         "markPrice": "96.83793449",
        //         "estLiqPrice": "0",
        //         "timestamp": 1752500555823,
        //         "adlQuantile": 2,
        //         "positionSide": "BOTH",
        //         "marginMode": "CROSS",
        //         "isolatedMarginToken": "",
        //         "isolatedMarginAmount": "0",
        //         "isolatedFrozenLong": "0",
        //         "isolatedFrozenShort": "0",
        //         "leverage": 10
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object contract = this.safeString(position, "symbol");
        market = this.safeMarket(contract, market);
        Object size = this.safeString(position, "holding");
        Object side = null;
        if (Helpers.isTrue(Precise.stringGt(size, "0")))
        {
            side = "long";
        } else
        {
            side = "short";
        }
        Object contractSize = this.safeString(market, "contractSize");
        Object markPrice = this.safeString2(position, "markPrice", "mark_price");
        Object timestampString = this.safeString(position, "timestamp");
        Object timestamp = null;
        if (Helpers.isTrue(!Helpers.isEqual(timestampString, null)))
        {
            if (Helpers.isTrue(Helpers.isGreaterThan(Helpers.getIndexOf(timestampString, "."), Helpers.opNeg(1))))
            {
                timestamp = this.safeTimestamp(position, "timestamp");
            } else
            {
                timestamp = this.safeInteger(position, "timestamp");
            }
        }
        Object entryPrice = this.safeString2(position, "averageOpenPrice", "average_open_price");
        Object priceDifference = Precise.stringSub(markPrice, entryPrice);
        Object unrealisedPnl = Precise.stringMul(priceDifference, size);
        size = Precise.stringAbs(size);
        Object notional = Precise.stringMul(size, markPrice);
        Object positionSide = this.safeString(position, "positionSide"); // 'SHORT' or 'LONG' for hedged, 'BOTH' for non-hedged
        final Object finalMarket = market;
        final Object finalTimestamp = timestamp;
        final Object finalSize = size;
        final Object finalSide = side;
        final Object finalPositionSide = positionSide;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", WooCore.this.safeString(finalMarket, "symbol") );
            put( "timestamp", finalTimestamp );
            put( "datetime", WooCore.this.iso8601(finalTimestamp) );
            put( "lastUpdateTimestamp", null );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "entryPrice", WooCore.this.parseNumber(entryPrice) );
            put( "notional", WooCore.this.parseNumber(notional) );
            put( "leverage", WooCore.this.safeNumber(position, "leverage") );
            put( "unrealizedPnl", WooCore.this.parseNumber(unrealisedPnl) );
            put( "contracts", WooCore.this.parseNumber(finalSize) );
            put( "contractSize", WooCore.this.parseNumber(contractSize) );
            put( "marginRatio", null );
            put( "liquidationPrice", WooCore.this.safeNumber2(position, "estLiqPrice", "est_liq_price") );
            put( "markPrice", WooCore.this.parseNumber(markPrice) );
            put( "lastPrice", null );
            put( "collateral", null );
            put( "marginMode", WooCore.this.safeStringLower2(position, "marginMode", "margin_mode") );
            put( "side", finalSide );
            put( "percentage", null );
            put( "hedged", !Helpers.isEqual(finalPositionSide, "BOTH") );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

